
import { defineComponent, ref } from "vue";
import { applyfor_details_history } from "@/server/http/api/Amultitasking";
const columns = [
  {
    title: "检测项名称",
    dataIndex: "checkItemName",
    key: "checkItemName",
  },
  {
    title: "单价",
    dataIndex: "checkPrice",
    key: "checkPrice",
  },
  {
    title: "检测样次",
    dataIndex: "times",
    key: "times",
  },
  {
    title: "检测方法",
    dataIndex: "methodName",
    key: "methodName",
  },
  {
    title: "检测依据",
    dataIndex: "standardName",
    key: "standardName",
  },
];
export default defineComponent({
  props: ["id"],
  setup(props) {
    let checkDetail = ref({});
    const visible = ref<boolean>(false);

    const showModal = () => {
      visible.value = true;
      applyfor_details_history(props.id).then((res: any) => {
        //console.log("报告历史详情", res);
        if (res.data.code === 200) {
          checkDetail.value = res.data.data;
        }
      });
    };

    const handleOk = (e: MouseEvent) => {
      //console.log(e);
      visible.value = false;
    };
    return {
      visible,
      showModal,
      handleOk,
      checkDetail,
      columns,
    };
  },
});
