const columns1 = [
  {
    title: "任务编号",
    dataIndex: "taskCode",
    key: "taskCode",
  },
  {
    title: "样品名称",
    dataIndex: "sampleName",
    key: "sampleName",
  },
  {
    title: "本单费用",
    dataIndex: "cost",
    key: "cost",
  },
  {
    title: "要求完成日期",
    key: "requiredCompletionTime",
    dataIndex: "requiredCompletionTime",
  },

  {
    title: "签发人",
    key: "issuer",
    dataIndex: "issuer",
  },

  {
    title: "报告提交申请人",
    key: "applicant",
    dataIndex: "applicant",
  },
  {
    title: "操作",
    key: "action",
    slots: { customRender: "action" },
  },
];

import { defineComponent, provide, reactive, ref, toRefs, watch } from "vue";
import GrabOrdersModel from "./model/Reportissuance/GrabOrdersModel.vue";
import ExamineModel from "./model/Reportissuance/ExamineModel.vue";
import GrabDetail from "./model/Reportissuance/GrabDetail.vue";
import ExamineDetail from "./model/Reportissuance/ExamineDetail.vue";
import { verify_list, verify_history } from "@/server/http/api/Amultitasking";
import { search } from "../ATaskdelegation/TaskalpubHook/getreleasedList";
export default defineComponent({
  name: "Reportapproval",
  components: { GrabOrdersModel, ExamineModel, GrabDetail, ExamineDetail },
  setup() {
    let active = ref(0);
    let total = ref(0);
    let options = reactive({
      searchValue: "",
      state: 0,
      pageNum: 1,
      pageSize: 10,
    });
    let searchValue1 = ref("");
    let datatList = ref([]);
    let datatList1 = ref([]);

    let timer: any;
    const searchList = () => {
      verify_list({
        search: options.searchValue,
        state: options.state,
        pageNum: options.pageNum,
        pageSize: options.pageSize,
      }).then((res: any) => {
        //console.log("报告审批init", res);
        if (res.data.code === 200) {
          datatList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    };

    // 历史查询
    function searchHistory() {
      verify_history({
        search: searchValue1.value,
        pageNum: options.pageNum,
        pageSize: options.pageSize,
      }).then((res: any) => {
        //console.log("报告审批历史", res);
        if (res.data.code === 200) {
          datatList1.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }
    // 监听历史数据
    watch(active, (newval) => {
      if (newval === 0) {
        searchList();
      } else {
        searchHistory();
      }
    });
    // 报告审批

    watch(
      options,
      () => {
        clearTimeout(timer);
        timer = setTimeout(() => {
          searchList();
        }, 400);
      },
      {
        immediate: true,
      }
    );

    watch(searchValue1, () => {
      clearTimeout(timer);

      timer = setTimeout(() => {
        searchHistory();
      }, 400);
    });
    // 报告签发
    provide("searchApplyfor", searchList);

    function onSearch() {}
    return {
      onSearch,
      datatList,
      columns,
      active,
      ...toRefs(options),
      columns1,
      total,
      datatList1,
      searchValue1,
    };
  },
});
